SELECT sr.response_id as responseId , sr.score_value as scoreValue , sr.text_value as textValue , DATE_FORMAT(sr.created_at, '%Y-%m-%d %H:%i:%s') as createdAt , sr.survey_id as surveyId , sr.question_id as questionId , sr.course_id as courseId , sr.loginID as loginId , s.title as surveyTitle , sq.content as questionContent , u.name as userName FROM survey_response sr LEFT JOIN survey s ON sr.survey_id = s.survey_id LEFT JOIN survey_question sq ON sr.question_id = sq.question_id LEFT JOIN tb_userinfo u ON sr.loginID = u.loginID
and sr.survey_id = #{surveyId}
and sr.loginID = #{loginId}
and sr.created_at >= STR_TO_DATE(#{from_date}, '%Y-%m-%d')
and sr.created_at <= STR_TO_DATE(#{to_date}, '%Y-%m-%d')
ORDER BY sr.response_id DESC LIMIT #{pageIndex}, #{pageSize}

SELECT COUNT(*)
FROM survey_response


		and survey_id = #{surveyId}


		and loginID = #{loginId}


		and created_at >= STR_TO_DATE(#{from_date}, '%Y-%m-%d')


		and created_at <= STR_TO_DATE(#{to_date}, '%Y-%m-%d')

